400→void ALFPTurnManager::PassTurn()
401→{
402→    if (bBattleEnded) return;
403→
404→    if (TurnOrderUnits.IsEmpty())
405→    {
406→        return;
407→    }
408→
409→    // 结束当前单位回合
410→    if (CurrentUnit)
411→    {
412→        EndUnitTurn(CurrentUnit);
413→    }
414→
415→    // 找到下一个未行动的单位
416→    int32 CurrentIndex = CurrentUnit ? TurnOrderUnits.Find(CurrentUnit) : -1;
417→    int32 StartIndex = (CurrentIndex + 1) % TurnOrderUnits.Num();
418→
419→    // 检查所有单位是否行动完毕
420→    bool TurnOrderUnitsActed = true;
421→    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
422→    {
423→        if (Unit && Unit->IsAlive() && !Unit->HasActed())
424→        {
425→            TurnOrderUnitsActed = false;
426→            break;
427→        }
428→    }
429→
430→    if (TurnOrderUnitsActed)
431→    {
432→        // 所有单位行动完毕，结束回合
433→        EndCurrentRound();
434→    }
435→    else
436→    {
437→        // 寻找下一个未行动单位
438→        for (int32 i = 0; i < TurnOrderUnits.Num(); i++)
439→        {
440→            int32 Index = (StartIndex + i) % TurnOrderUnits.Num();
441→            ALFPTacticsUnit* NextUnit = TurnOrderUnits[Index];
442→
443→            if (NextUnit && NextUnit->IsAlive() && !NextUnit->HasActed())
444→            {
445→                BeginUnitTurn(NextUnit);
446→                return;
447→            }
448→        }
449→
450→        // 没有找到未行动单位，结束回合
451→        EndCurrentRound();
452→    }
453→}
