184→bool ALFPTacticsUnit::MoveToTile(ALFPHexTile* NewTargetTile)
185→{
186→    if (!NewTargetTile || !HasEnoughMovePoints(1)) return false;
187→
188→    ALFPHexGridManager* GridManager = GetGridManager();
189→    if (!GridManager) return false;
190→
191→    // 获取当前所在的格子
192→    ALFPHexTile* CurrentTile = GridManager->GetTileAtCoordinates(CurrentCoordinates);
193→    if (!CurrentTile) return false;
194→
195→    // 寻找路径（FindPath 返回的路径不包含起点）
196→    MovePath = GridManager->FindPath(CurrentTile, NewTargetTile);
197→    // 计算路径实际移动代价（考虑地形）
198→    int32 PathCost = 0;
199→    for (ALFPHexTile* Tile : MovePath)
200→    {
201→        PathCost += Tile->GetMovementCost();
202→    }
203→    if (MovePath.Num() == 0 || PathCost > CurrentMovePoints) return false;
204→
205→    // 在路径开头插入当前格子，使 Tick 中 MovePath[0] → MovePath[1] 为第一段移动
206→    MovePath.Insert(CurrentTile, 0);
207→
208→    // 设置移动状态
209→    CurrentTile->SetIsOccupied(false);
210→    TargetTile = NewTargetTile;
211→    CurrentPathIndex = 0;
212→    MoveProgress = 0.0f;
213→    MovementRangeTiles.Empty();
214→
215→    // 启动移动动画（Tick 驱动逐格插值）
216→    bIsMoving = true;
217→
218→    return true;
219→}
