226→void ALFPTacticsUnit::FinishMove()
227→{
228→    bIsMoving = false;
229→
230→    // 更新到目标位置
231→    if (TargetTile)
232→    {
233→        SetCurrentCoordinates(TargetTile->GetCoordinates());
234→        // 计算路径实际移动代价（跳过 MovePath[0] 即起点格子）
235→        int32 TotalCost = 0;
236→        for (int32 i = 1; i < MovePath.Num(); i++)
237→        {
238→            TotalCost += MovePath[i]->GetMovementCost();
239→        }
240→        ConsumeMovePoints(TotalCost);
241→    }
242→
243→    // 清除移动状态
244→    TargetTile = nullptr;
245→    MovePath.Empty();
246→    CurrentPathIndex = -1;
247→    MoveProgress = 0.0f;
248→
249→    // 广播移动完成
250→    OnMoveFinished.Broadcast();
251→}
