591→ALFPTacticsUnit* ALFPTacticsUnit::FindBestTarget()
592→{
593→    // 获取所有玩家单位
594→    TArray<AActor*> PlayerUnits;
595→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), PlayerUnits);
596→
597→    ALFPTacticsUnit* BestTarget = nullptr;
598→    float BestThreatValue = -MAX_FLT;
599→
600→    for (AActor* Actor : PlayerUnits)
601→    {
602→        ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor);
603→        if (Unit && Unit->IsAlive() && Unit->IsAlly())
604→        {
605→            float ThreatValue = CalculateThreatValue(Unit);
606→            if (ThreatValue > BestThreatValue)
607→            {
608→                BestThreatValue = ThreatValue;
609→                BestTarget = Unit;
610→            }
611→        }
612→    }
613→
614→    return BestTarget;
615→}
