620→    if (!GridManager)
621→    {
622→        return nullptr;
623→    }
624→    // 获取所有可移动位置
625→    MovementRangeTiles = GridManager->GetTilesInRange(GetCurrentTile(), GetCurrentMovePoints());
626→
627→    ALFPHexTile* BestTile = nullptr;
628→    float BestPositionValue = -MAX_FLT;
629→
630→    for (ALFPHexTile* Tile : MovementRangeTiles)
631→    {
632→        // 跳过有单位的格子
633→        if (Tile->GetUnitOnTile()) continue;
634→
635→        float PositionValue = CalculatePositionValue(Tile, Target);
636→        if (PositionValue > BestPositionValue)
637→        {
638→            BestPositionValue = PositionValue;
639→            BestTile = Tile;
640→        }
641→    }
642→
643→    return BestTile;
644→}
