730→TArray<ALFPHexTile*> ALFPTacticsUnit::GetAttackRangeTiles()
731→{
732→    TArray<ALFPHexTile*> AttackRangeTiles;
733→
734→    if (ALFPHexGridManager* GridManager = GetGridManager())
735→    {
736→        // 近战攻击范围
737→        if (bMeleeAttack)
738→        {
739→            // 获取相邻格子
740→            TArray<FLFPHexCoordinates> Neighbors = CurrentCoordinates.GetNeighbors();
741→            for (const FLFPHexCoordinates& Coord : Neighbors)
742→            {
743→                FLFPHexCoordinates Key(Coord.Q, Coord.R);
744→                if (ALFPHexTile* Tile = GridManager->GetTileAtCoordinates(Key))
745→                {
746→                    AttackRangeTiles.Add(Tile);
747→                }
748→            }
749→        }
750→        // 远程攻击范围
751→        else
752→        {
753→            // 获取攻击范围内的所有格子
754→            TArray<ALFPHexTile*> TilesInRange = GridManager->GetTilesInRange(GetCurrentTile(), AttackRange);
755→
756→            for (ALFPHexTile* Tile : TilesInRange)
757→            {
758→                AttackRangeTiles.Add(Tile);
759→            }
760→        }
761→    }
762→
763→    return AttackRangeTiles;
764→}
