766→bool ALFPTacticsUnit::IsTargetInAttackRange(ALFPTacticsUnit* Target) const
767→{
768→    if (!Target || !Target->GetCurrentTile()) return false;
769→
770→    // 计算距离
771→    int32 Distance = FLFPHexCoordinates::Distance(
772→        CurrentCoordinates,
773→        Target->GetCurrentCoordinates()
774→    );
775→
776→    // 近战攻击判定
777→    if (bMeleeAttack)
778→    {
779→        return Distance == 1; // 相邻格子
780→    }
781→    // 远程攻击判定
782→    else
783→    {
784→        return Distance >= 2 && Distance <= AttackRange;
785→    }
786→}
