 69→void ALFPTurnGameMode::EndBattle(bool bVictory, bool bEscaped)
 70→{
 71→    ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
 72→    if (!GI) return;
 73→
 74→    // 构建战斗结果
 75→    FLFPBattleResult Result;
 76→    Result.SourceNodeID = CachedBattleRequest.SourceNodeID;
 77→    Result.bVictory = bVictory;
 78→    Result.bEscaped = bEscaped;
 79→
 80→    if (bVictory)
 81→    {
 82→        Result.CapturedUnits = CapturedUnits;
 83→        // 总奖励 = 基础奖励 + 击杀掉落
 84→        Result.GoldReward = CachedBattleRequest.BaseGoldReward + AccumulatedDropGold;
 85→        Result.FoodReward = CachedBattleRequest.BaseFoodReward + AccumulatedDropFood;
 86→    }
 87→    // 逃跑或失败：不给奖励（默认 0）
 88→
 89→    // 缓存结果，确认后写回
 90→    CachedBattleResult = Result;
 91→
 92→    // 显示结算 UI
 93→    if (BattleResultWidgetClass)
 94→    {
 95→        APlayerController* PC = GetWorld()->GetFirstPlayerController();
 96→        if (PC)
 97→        {
 98→            BattleResultWidget = CreateWidget<ULFPBattleResultWidget>(PC, BattleResultWidgetClass);
 99→            if (BattleResultWidget)
100→            {
101→                BattleResultWidget->Setup(Result, GI->UnitRegistry);
102→                BattleResultWidget->OnConfirmPressed.AddDynamic(this, &ALFPTurnGameMode::OnBattleResultConfirmed);
103→                BattleResultWidget->AddToViewport(100);
104→
105→                // 切换到 UI 输入模式
106→                FInputModeUIOnly InputMode;
107→                InputMode.SetWidgetToFocus(BattleResultWidget->TakeWidget());
108→                PC->SetInputMode(InputMode);
109→                PC->SetShowMouseCursor(true);
110→            }
111→        }
112→    }
113→    else
114→    {
115→        // 无 Widget 类配置，直接返回（兼容测试场景）
116→        OnBattleResultConfirmed();
117→    }
118→}
119→
120→void ALFPTurnGameMode::OnBattleResultConfirmed()
121→{
122→    ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
123→    if (!GI) return;
124→
125→    // 写回战斗结果
126→    GI->SetBattleResult(CachedBattleResult);
127→
128→    // 移除结算 UI
129→    if (BattleResultWidget)
130→    {
131→        BattleResultWidget->OnConfirmPressed.RemoveDynamic(this, &ALFPTurnGameMode::OnBattleResultConfirmed);
132→        BattleResultWidget->RemoveFromParent();
133→        BattleResultWidget = nullptr;
134→    }
135→
136→    // 恢复输入模式
137→    if (APlayerController* PC = GetWorld()->GetFirstPlayerController())
138→    {
139→        FInputModeGameAndUI InputMode;
140→        PC->SetInputMode(InputMode);
141→    }
142→
143→    // 返回世界地图
144→    if (CachedBattleRequest.bIsValid)
145→    {
146→        GI->TransitionToWorldMap(TEXT(""));
147→    }
148→}
