  8→#include "Kismet/GameplayStatics.h"
  9→#include "Camera/PlayerCameraManager.h"
 10→#include "EnhancedInputComponent.h"
 11→#include "EnhancedInputSubsystems.h"
 12→
 13→ALFPWorldMapPlayerController::ALFPWorldMapPlayerController()
 14→{
 15→	CameraOffset = FVector::ZeroVector;
 16→
 17→	// 创建世界地图编辑器组件
 18→	WorldMapEditorComponent = CreateDefaultSubobject<ULFPWorldMapEditorComponent>(TEXT("WorldMapEditorComponent"));
 19→}
 20→
 21→void ALFPWorldMapPlayerController::BeginPlay()
 22→{
 23→	Super::BeginPlay();
 24→
 25→	// 设置输入模式
 26→	FInputModeGameAndUI InputMode;
 27→	InputMode.SetLockMouseToViewportBehavior(EMouseLockMode::DoNotLock);
 28→	InputMode.SetHideCursorDuringCapture(false);
 29→	SetInputMode(InputMode);
 30→	bShowMouseCursor = true;
 31→
 32→	// 设置 Enhanced Input
 33→	if (UEnhancedInputLocalPlayerSubsystem* Subsystem = ULocalPlayer::GetSubsystem<UEnhancedInputLocalPlayerSubsystem>(GetLocalPlayer()))
 34→	{
 35→		if (DefaultInputMapping)
 36→		{
 37→			Subsystem->AddMappingContext(DefaultInputMapping, 0);
 38→		}
 39→	}
 40→
 41→	// 场景切换淡入效果
 42→	if (PlayerCameraManager)
 43→	{
 44→		ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
 45→		float FadeDuration = GI ? GI->TransitionFadeDuration : 0.5f;
 46→		PlayerCameraManager->StartCameraFade(1.f, 0.f, FadeDuration, FLinearColor::Black, false, false);
 47→	}
 48→
 49→	// 首帧跳过相机平滑插值
 50→	bSnapCameraNextFrame = true;
 51→}
 52→
 53→void ALFPWorldMapPlayerController::Tick(float DeltaTime)
 54→{
 55→	Super::Tick(DeltaTime);
 56→
 57→	if (bIsDragging)
 58→	{
 59→		DragTime += DeltaTime;
 60→	}
 61→
 62→	// 更新相机位置和旋转
 63→	// 相机位置：CameraOffset（XY 平移）+ CurrentZoom（高度）
 64→	FVector TargetLocation = CameraOffset + FVector(0.f, 0.f, CurrentZoom);
 65→
 66→	// 相机旋转：俯视角
 67→	FRotator TargetRotation(CameraPitchAngle, 0.f, 0.f);
 68→
 69→	// 平滑插值并设置
 70→	FRotator CurrentRotation = GetControlRotation();
 71→	if (bSnapCameraNextFrame)
 72→	{
 73→		SetControlRotation(TargetRotation);
 74→	}
 75→	else
 76→	{
 77→		SetControlRotation(FMath::RInterpTo(CurrentRotation, TargetRotation, DeltaTime, 5.0f));
 78→	}
 79→
 80→	// 通过 Pawn 控制相机位置（如果有 Pawn）
 81→	if (APawn* ControlledPawn = GetPawn())
 82→	{
 83→		if (bSnapCameraNextFrame)
 84→		{
 85→			// 首帧直接跳到目标位置，避免切场景后相机大幅滑动
 86→			ControlledPawn->SetActorLocation(TargetLocation);
 87→			bSnapCameraNextFrame = false;
 88→		}
 89→		else
 90→		{
 91→			FVector CurrentLocation = ControlledPawn->GetActorLocation();
 92→			ControlledPawn->SetActorLocation(
 93→				FMath::VInterpTo(CurrentLocation, TargetLocation, DeltaTime, 5.0f)
 94→			);
 95→		}
 96→	}
 97→}
 98→
 99→void ALFPWorldMapPlayerController::SetupInputComponent()
100→{
101→	Super::SetupInputComponent();
102→
103→	if (UEnhancedInputComponent* EnhancedInputComponent = Cast<UEnhancedInputComponent>(InputComponent))
104→	{
105→		// 基础操作
106→		EnhancedInputComponent->BindAction(ConfirmAction, ETriggerEvent::Completed, this, &ALFPWorldMapPlayerController::OnConfirmAction);
107→		EnhancedInputComponent->BindAction(CancelAction, ETriggerEvent::Completed, this, &ALFPWorldMapPlayerController::OnCancelAction);
108→
109→		// 相机操作
110→		EnhancedInputComponent->BindAction(CameraPanAction, ETriggerEvent::Triggered, this, &ALFPWorldMapPlayerController::OnCameraPan);
111→		EnhancedInputComponent->BindAction(CameraDragAction, ETriggerEvent::Started, this, &ALFPWorldMapPlayerController::OnCameraDragStarted);
112→		EnhancedInputComponent->BindAction(CameraDragAction, ETriggerEvent::Triggered, this, &ALFPWorldMapPlayerController::OnCameraDragTriggered);
113→		EnhancedInputComponent->BindAction(CameraDragAction, ETriggerEvent::Completed, this, &ALFPWorldMapPlayerController::OnCameraDragCompleted);
114→		EnhancedInputComponent->BindAction(CameraZoomAction, ETriggerEvent::Triggered, this, &ALFPWorldMapPlayerController::OnCameraZoom);
115→
116→		// 编辑器切换
117→		EnhancedInputComponent->BindAction(ToggleEditorAction, ETriggerEvent::Started, this, &ALFPWorldMapPlayerController::OnToggleEditorAction);
118→	}
119→}
120→
121→// ============== 输入处理 ==============
122→
123→void ALFPWorldMapPlayerController::OnConfirmAction(const FInputActionValue& Value)
124→{
125→	bIsDragging = false;
126→	if (DragTime > DragThresholdTime)
127→	{
128→		DragTime = 0.f;
129→		return;
130→	}
131→	DragTime = 0.f;
132→
133→	// 编辑器模式优先处理
134→	if (WorldMapEditorComponent && WorldMapEditorComponent->IsEditorActive())
135→	{
136→		// 射线检测点击的节点
137→		FHitResult HitResult;
138→		GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
139→		ALFPWorldMapNode* ClickedNode = Cast<ALFPWorldMapNode>(HitResult.GetActor());
140→
141→		ELFPWorldMapEditorTool CurrentTool = WorldMapEditorComponent->GetCurrentTool();
142→
143→		switch (CurrentTool)
144→		{
145→		case ELFPWorldMapEditorTool::WMET_PlaceNode:
146→			{
147→				// 射线投射到 Z=0 平面获取世界坐标
148→				FVector WorldOrigin, WorldDirection;
149→				DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
150→				if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
151→				{
152→					float T = -WorldOrigin.Z / WorldDirection.Z;
153→					FVector HitPoint = WorldOrigin + WorldDirection * T;
154→					WorldMapEditorComponent->PlaceNodeAt(FVector2D(HitPoint.X, HitPoint.Y));
155→				}
156→			}
157→			break;
158→
159→		case ELFPWorldMapEditorTool::WMET_RemoveNode:
160→			if (ClickedNode)
161→			{
162→				WorldMapEditorComponent->SelectNode(ClickedNode);
163→				WorldMapEditorComponent->RemoveSelectedNode();
164→			}
165→			break;
166→
167→		case ELFPWorldMapEditorTool::WMET_MoveNode:
168→			if (ClickedNode)
169→			{
170→				WorldMapEditorComponent->SelectNode(ClickedNode);
171→			}
172→			else if (WorldMapEditorComponent->GetSelectedNode())
173→			{
174→				// 移动到点击位置
175→				FVector WorldOrigin, WorldDirection;
176→				DeprojectMousePositionToWorld(WorldOrigin, WorldDirection);
177→				if (FMath::Abs(WorldDirection.Z) > KINDA_SMALL_NUMBER)
178→				{
179→					float T = -WorldOrigin.Z / WorldDirection.Z;
180→					FVector HitPoint = WorldOrigin + WorldDirection * T;
181→					WorldMapEditorComponent->MoveSelectedNodeTo(FVector2D(HitPoint.X, HitPoint.Y));
182→				}
183→			}
184→			break;
185→
186→		case ELFPWorldMapEditorTool::WMET_ConnectEdge:
187→			if (ClickedNode)
188→			{
189→				WorldMapEditorComponent->HandleEdgeConnection(ClickedNode);
190→			}
191→			break;
192→
193→		case ELFPWorldMapEditorTool::WMET_RemoveEdge:
194→			if (ClickedNode)
195→			{
196→				WorldMapEditorComponent->HandleEdgeRemoval(ClickedNode);
197→			}
198→			break;
199→
200→		case ELFPWorldMapEditorTool::WMET_SetNodeParams:
201→			if (ClickedNode)
202→			{
203→				WorldMapEditorComponent->SelectNode(ClickedNode);
204→				WorldMapEditorComponent->ApplyParamsToSelectedNode();
205→			}
206→			break;
207→
208→		default:
209→			break;
210→		}
211→		return;
212→	}
213→
214→	// 游戏模式：点击节点移动或进入
215→	FHitResult HitResult;
216→	GetHitResultUnderCursor(ECC_Visibility, false, HitResult);
217→	ALFPWorldMapNode* ClickedNode = Cast<ALFPWorldMapNode>(HitResult.GetActor());
218→
219→	if (ClickedNode)
220→	{
221→		ALFPWorldMapManager* Manager = GetWorldMapManager();
222→		if (!Manager || !Manager->GetPlayerState()) return;
223→
224→		int32 CurrentNodeID = Manager->GetPlayerState()->CurrentNodeID;
225→
226→		// 点击当前节点 → 进入节点
227→		if (ClickedNode->NodeID == CurrentNodeID)
228→		{
229→			EnterNode(ClickedNode);
230→			return;
231→		}
232→
233→		// 点击相邻可达节点 → 移动
234→		TArray<int32> ReachableIDs = Manager->GetPlayerState()->GetReachableNodeIDs(Manager);
235→		if (ReachableIDs.Contains(ClickedNode->NodeID))
236→		{
237→			MoveToNode(ClickedNode);
238→		}
239→		else
240→		{
241→			// 不可达，只选中
242→			SelectNode(ClickedNode);
243→		}
244→	}
245→}
246→
247→void ALFPWorldMapPlayerController::OnCancelAction(const FInputActionValue& Value)
248→{
249→	// 取消选中和可达高亮
250→	ClearReachableHighlight();
251→	if (SelectedNode)
252→	{
253→		SelectedNode->SetHighlighted(false);
254→		SelectedNode = nullptr;
255→	}
256→}
257→
258→void ALFPWorldMapPlayerController::OnToggleEditorAction(const FInputActionValue& Value)
259→{
260→	if (!WorldMapEditorComponent) return;
261→
262→	WorldMapEditorComponent->ToggleEditorMode();
263→
264→	if (WorldMapEditorComponent->IsEditorActive())
265→	{
266→		// 创建或显示编辑器 Widget
267→		if (!WorldMapEditorWidget && WorldMapEditorWidgetClass)
268→		{
269→			WorldMapEditorWidget = CreateWidget<ULFPWorldMapEditorWidget>(this, WorldMapEditorWidgetClass);
270→			if (WorldMapEditorWidget)
271→			{
272→				WorldMapEditorWidget->AddToViewport();
273→				WorldMapEditorWidget->InitializeEditor(WorldMapEditorComponent);
274→			}
275→		}
276→		else if (WorldMapEditorWidget)
277→		{
278→			WorldMapEditorWidget->SetVisibility(ESlateVisibility::Visible);
279→		}
280→
281→		bShowMouseCursor = true;
282→	}
283→	else
284→	{
285→		// 隐藏编辑器 Widget
286→		if (WorldMapEditorWidget)
287→		{
288→			WorldMapEditorWidget->SetVisibility(ESlateVisibility::Collapsed);
289→		}
290→	}
291→}
292→
293→// ============== 相机操作 ==============
294→
295→void ALFPWorldMapPlayerController::OnCameraPan(const FInputActionValue& Value)
296→{
297→	FVector2D PanInput = Value.Get<FVector2D>();
298→	CameraOffset += FVector(PanInput.X, PanInput.Y, 0) * CameraPanSpeed * GetWorld()->GetDeltaSeconds();
299→}
300→
301→void ALFPWorldMapPlayerController::OnCameraDragStarted(const FInputActionValue& Value)
302→{
303→	bIsDragging = true;
304→	DragTime = 0.f;
305→	GetMousePosition(DragStartPosition.X, DragStartPosition.Y);
306→}
307→
308→void ALFPWorldMapPlayerController::OnCameraDragTriggered(const FInputActionValue& Value)
309→{
310→	if (!bIsDragging) return;
311→
312→	FVector2D CurrentMousePos;
313→	GetMousePosition(CurrentMousePos.X, CurrentMousePos.Y);
314→	FVector2D Delta = CurrentMousePos - DragStartPosition;
315→
316→	CameraOffset -= FVector(-Delta.Y, Delta.X, 0) * CameraDragSpeed;
317→	DragStartPosition = CurrentMousePos;
